<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    @* ── Summary stats bar ── *@
    <div class="row g-2 mb-3">
        <div class="col"><div class="stats-card bg-primary bg-opacity-10 border-primary">Total <strong>@_allTasks.Count</strong></div></div>
        <div class="col"><div class="stats-card bg-secondary bg-opacity-10 border-secondary">To Do <strong>@TodoTasks.Count()</strong></div></div>
        <div class="col"><div class="stats-card bg-info bg-opacity-10 border-info">In Progress <strong>@InProgressTasks.Count()</strong></div></div>
        <div class="col"><div class="stats-card bg-success bg-opacity-10 border-success">Done <strong>@DoneTasks.Count()</strong></div></div>
        <div class="col"><div class="stats-card bg-danger bg-opacity-10 border-danger">Overdue <strong>@OverdueCount</strong></div></div>
    </div>

    @* ── Search bar ── *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    @* ── Kanban columns ── *@
    <div class="row g-3 board-row">
        @foreach (var col in _columns)
        {
            var tasks = GetFilteredTasks(col);
            var colIndex = Array.IndexOf(_columns, col);

            <div class="col-md-4">
                <div class="card kanban-column h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <span class="fw-bold">@col</span>
                        <span class="badge bg-secondary rounded-pill">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto kanban-body">
                        @foreach (var task in tasks)
                        {
                            <div class="card task-card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1 mt-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_updating"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < _columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_updating"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @* ── Inline add-task form ── *@
                        @if (_addingColumn == col)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="() => SaveTaskAsync(col)">
                                            Save
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                @onclick="CancelAdd">
                                            Cancel
                                        </button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>

                    @if (_addingColumn != col)
                    {
                        <div class="card-footer text-center">
                            <button class="btn btn-outline-primary btn-sm w-100"
                                    @onclick="() => StartAdd(col)">
                                + Add Task
                            </button>
                        </div>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private bool _updating;
    private bool _saving;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    // Filtered task helpers
    private IEnumerable<TaskItem> TodoTasks => _allTasks.Where(t => t.Status == "To Do");
    private IEnumerable<TaskItem> InProgressTasks => _allTasks.Where(t => t.Status == "In Progress");
    private IEnumerable<TaskItem> DoneTasks => _allTasks.Where(t => t.Status == "Done");
    private int OverdueCount => _allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync() ?? new();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = _allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(_searchText))
        {
            tasks = tasks.Where(t =>
                t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        _updating = true;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _updating = false;
        }
    }

    private void StartAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        _saving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(
                _newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);

            // CreateTaskAsync may not set the column status, so ensure it matches
            var withStatus = created with { Status = column };
            _allTasks.Add(withStatus);

            if (column != created.Status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
            }

            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}
"}

